def tokenize(s):
    s = normalize_arabic(s)
    return s.split()

def token_f1(a, b):
    ta, tb = tokenize(a), tokenize(b)
    ca = {}
    cb = {}
    for t in ta:
        ca[t] = ca.get(t,0)+1
    for t in tb:
        cb[t] = cb.get(t,0)+1
    # Compute overlap counts
    overlap = 0
    for t in set(ca) & set(cb):
        overlap += min(ca[t], cb[t])
    precision = overlap / len(ta) if ta else 0.0
    recall = overlap / len(tb) if tb else 0.0
    if precision+recall == 0:
        f1 = 0.0
    else:
        f1 = 2*precision*recall/(precision+recall)
    return precision, recall, f1

def lcs_ratio(a, b):
    # normalized length of LCS over max length (in characters)
    A = normalize_arabic(a)
    B = normalize_arabic(b)
    # dynamic programming LCS length
    # beware complexity; strings may be 1000 char. We'll use SequenceMatcher's ratio as LCS approx or implement minimal DP.
    # We'll just use SequenceMatcher ratio as char-based similarity
    return SequenceMatcher(None, A, B).ratio()

